+fn file_has_magic_prefix(path: &Path, expected: &[u8]) -> bool {
+    let mut buffer = vec![0; expected.len()];
+    let Ok(mut file) = File::open(path) else {
+        return false;
+    };
+    if file.read_exact(&mut buffer).is_err() {
+        return false;
+    }
+
+    buffer == expected
+}
